import os
import json
import math
import base64
import traceback
import subprocess
import sys
from flask import Flask, request, jsonify, Response
from flask_cors import CORS
 
app = Flask(__name__)
CORS(app)
 
ANTHROPIC_API_KEY = os.environ.get("ANTHROPIC_API_KEY", "")
MAX_PAGES_PER_CHUNK = 80
MAX_FILE_BYTES = 900 * 1024 * 1024
app.config["MAX_CONTENT_LENGTH"] = MAX_FILE_BYTES
 
_HTML_B64 = ""
INDEX_HTML = base64.b64decode(_HTML_B64).decode("utf-8")
 
SYSTEM_PROMPT = 'You are an expert appellate attorney and legal analyst. Analyze this court of appeals record with the thoroughness of a senior attorney preparing for oral argument. Produce a comprehensive, detailed summary.\n\nReturn ONLY valid JSON — no markdown fences, no preamble, nothing else.\n\nThe JSON must have exactly these keys:\n{\n  "caseTitle": "Full case name and cause number if identifiable",\n  "pleadings": [...],\n  "witnesses": [...],\n  "dispositiveMotions": [...],\n  "ordersAndJudgments": [...],\n  "trial": { ... },\n  "pretrialMatters": [...],\n  "trialObjections": [...]\n}\n\nPLEADINGS — identify every pleading filed. For each:\n{ "date": "date filed", "title": "full title of the pleading", "type": "Petition|Original Answer|Amended Answer|Affirmative Defense|Third-Party Petition|Counterclaim|Cross-Claim|Intervention|Special Exceptions|other", "summary": "3-5 sentence detailed summary of the substance and allegations, including specific legal theories, parties, and relief sought" }\n\nWITNESSES — every person who gave testimony by affidavit, declaration, deposition, or at trial. For each:\n{ "name": "full name and title/role if known", "date": "date of testimony", "type": "Affidavit|Declaration|Deposition|Trial Testimony", "keyTestimony": ["detailed bullet point 1 — specific facts, opinions, or admissions", "bullet 2", "bullet 3 — include at least 5 bullet points per witness with specific detail"] }\n\nDISPOSITIVE MOTIONS — every motion that could terminate the case. For each:\n{ "date": "date filed", "title": "full title", "type": "Motion to Dismiss|Motion for Summary Judgment|Plea to the Jurisdiction|Motion for Directed Verdict|Motion for JNOV|Motion to Strike|other", "filedBy": "party name", "mainArguments": ["argument 1 with specifics", "argument 2", "argument 3 — list every distinct argument made"], "courtRuling": "detailed description of ruling including legal basis stated by court", "rulingDate": "date of ruling" }\n\nORDERS AND JUDGMENTS — every order, ruling, and judgment. For each:\n{ "date": "date", "title": "full title", "type": "Interlocutory Order|Final Judgment|Partial Summary Judgment|Order on Motion|Scheduling Order|Discovery Order|Sanctions Order|other", "summary": "3-4 sentence description of what the order required, granted, or denied, and any legal findings stated", "significance": "1-2 sentences explaining why this order matters to the case outcome" }\n\nTRIAL — if a trial occurred:\n{ "occurred": true, "startDate": "date", "endDate": "date", "summary": "3-5 sentence overview of what the trial was about and how it proceeded", "days": [ { "dayNumber": 1, "date": "date", "description": "paragraph describing the day including procedural events", "witnesses": ["witness name 1", "witness name 2"], "significantEvents": ["event 1 with detail", "event 2", "event 3"] } ], "exhibits": [ { "id": "exhibit number or letter", "description": "detailed description of what the exhibit is", "offeredBy": "party", "date": "date offered", "admitted": true, "reason": "basis for admission or reason for exclusion" } ] }\n\nPRETRIAL MATTERS — all pretrial orders, motions in limine, and pretrial rulings. For each:\n{ "date": "date", "title": "full title", "type": "Motion in Limine|Pretrial Order|Scheduling Order|Pretrial Conference|Discovery Dispute|Sanctions|other", "summary": "3-4 sentences describing what was sought and the legal basis", "ruling": "detailed description of ruling" }\n\nTRIAL OBJECTIONS — every objection made at trial. For each:\n{ "date": "date", "objectingParty": "party name", "basis": "specific legal basis (hearsay, relevance, 403, foundation, etc.)", "evidenceOrTestimony": "specific description of what was being offered and by whom", "courtRuling": "how the court ruled and any explanation given", "sustained": true or false }\n\nIMPORTANT INSTRUCTIONS:\n- Be exhaustive — identify every document, witness, motion, and order in the record\n- Write summaries in complete sentences with specific facts, not vague generalities\n- Include specific dates, party names, dollar amounts, and legal standards wherever they appear\n- For witnesses, include their specific testimony content not just topics\n- If a section has no items, return an empty array (or for trial, occurred: false)\n- For dates use the format found in the document'
 
MERGE_PROMPT = 'You are an expert appellate attorney. Merge all the partial summaries below into one comprehensive, deduplicated summary.\n\nReturn ONLY valid JSON with exactly these keys: caseTitle, pleadings, witnesses, dispositiveMotions, ordersAndJudgments, trial, pretrialMatters, trialObjections.\n\nRules:\n- Deduplicate: if the same document/witness/event appears in multiple chunks, keep only one entry with the most detail\n- Merge witness testimony: if the same witness appears in multiple chunks, combine their testimony bullet points\n- For trial: if any chunk shows occurred: true, set occurred: true and merge all days, exhibits, and summary\n- Keep all unique entries from all chunks\n- Maintain the same detailed level of description from the partial summaries\n\nPartial summaries to merge:\n'
 
def make_client():
    import anthropic
    try:
        return anthropic.Anthropic(api_key=ANTHROPIC_API_KEY)
    except TypeError:
        os.environ["ANTHROPIC_API_KEY"] = ANTHROPIC_API_KEY
        return anthropic.Anthropic()
 
@app.route("/")
def index():
    return Response(INDEX_HTML, mimetype="text/html")
 
@app.route("/health")
def health():
    return jsonify({"status":"ok","html_chars":len(INDEX_HTML),"api_key_set":bool(ANTHROPIC_API_KEY),"python":sys.version})
 
@app.route("/versions")
def versions():
    try:
        result = subprocess.run([sys.executable,"-m","pip","list","--format=json"],capture_output=True,text=True,timeout=10)
        pkgs = json.loads(result.stdout)
        wanted = {p["name"].lower():p["version"] for p in pkgs if p["name"].lower() in ("anthropic","httpx","flask","pymupdf","fitz")}
        return jsonify(wanted)
    except Exception as e:
        return jsonify({"error":str(e)})
 
@app.route("/analyze", methods=["POST"])
def analyze():
    try:
        return _analyze()
    except Exception as e:
        print("UNHANDLED ERROR:\n", traceback.format_exc())
        return jsonify({"error":f"Unexpected server error: {str(e)}"}), 500
 
def _analyze():
    if not ANTHROPIC_API_KEY:
        return jsonify({"error":"Server is missing ANTHROPIC_API_KEY. Add it in Render dashboard under Environment."}), 500
    if "file" not in request.files:
        return jsonify({"error":"No file received."}), 400
    f = request.files["file"]
    fname = f.filename or ""
    if not fname.lower().endswith(".pdf"):
        return jsonify({"error":"Please upload a PDF file."}), 400
    try:
        pdf_bytes = f.read()
    except Exception as e:
        return jsonify({"error":f"Failed to read file: {str(e)}"}), 400
    if not pdf_bytes:
        return jsonify({"error":"The uploaded file is empty."}), 400
    mb = len(pdf_bytes)/1048576
    print(f"File: {fname}  {mb:.1f} MB")
    if len(pdf_bytes) > MAX_FILE_BYTES:
        return jsonify({"error":f"File is {mb:.0f} MB. Maximum is 900 MB."}), 400
    import fitz
    try:
        doc = fitz.open(stream=pdf_bytes, filetype="pdf")
    except Exception as e:
        return jsonify({"error":f"Could not open PDF (corrupted or password-protected): {str(e)}"}), 400
    total_pages = len(doc)
    print(f"Pages: {total_pages}")
    try:
        client = make_client()
    except Exception as e:
        return jsonify({"error":f"Could not initialise AI client: {str(e)}"}), 500
    if total_pages <= MAX_PAGES_PER_CHUNK and len(pdf_bytes) <= 32*1024*1024:
        doc.close()
        print("Strategy: direct base64")
        try:
            return jsonify(analyze_pdf_bytes(client, pdf_bytes))
        except Exception as e:
            print("Direct error:\n", traceback.format_exc())
            return jsonify({"error":f"Analysis failed: {str(e)}"}), 500
    n = math.ceil(total_pages/MAX_PAGES_PER_CHUNK)
    print(f"Strategy: chunked text ({n} chunks)")
    try:
        partials = analyze_in_chunks(client, doc, total_pages)
        doc.close()
    except Exception as e:
        doc.close()
        print("Chunk error:\n", traceback.format_exc())
        return jsonify({"error":f"Analysis failed during text extraction: {str(e)}"}), 500
    if not partials:
        return jsonify({"error":"No readable text found. The PDF may be a scanned image without OCR text."}), 400
    try:
        result = partials[0] if len(partials)==1 else merge_results(client, partials)
        return jsonify(result)
    except Exception as e:
        print("Merge error:\n", traceback.format_exc())
        return jsonify({"error":f"Analysis failed during merge: {str(e)}"}), 500
 
def analyze_pdf_bytes(client, pdf_bytes):
    b64 = base64.b64encode(pdf_bytes).decode("utf-8")
    r = client.messages.create(
        model="claude-sonnet-4-20250514", max_tokens=8000, system=SYSTEM_PROMPT,
        messages=[{"role":"user","content":[
            {"type":"document","source":{"type":"base64","media_type":"application/pdf","data":b64}},
            {"type":"text","text":"Analyze this appellate court record and return the structured JSON summary."}
        ]}]
    )
    return parse_json(r.content[0].text)
 
def analyze_in_chunks(client, doc, total_pages):
    results = []
    n = math.ceil(total_pages/MAX_PAGES_PER_CHUNK)
    for i in range(n):
        start = i*MAX_PAGES_PER_CHUNK
        end = min(start+MAX_PAGES_PER_CHUNK, total_pages)
        label = f"pages {start+1}-{end} of {total_pages}"
        print(f"  Chunk {i+1}/{n}: {label}")
        parts = []
        for p in range(start, end):
            t = doc[p].get_text("text")
            if t.strip():
                parts.append(f"[Page {p+1}]\n{t}")
        text = "\n\n".join(parts)
        if not text.strip():
            print("    No text, skipping")
            continue
        try:
            r = client.messages.create(
                model="claude-sonnet-4-20250514", max_tokens=8000, system=SYSTEM_PROMPT,
                messages=[{"role":"user","content":f"Analyze this section ({label}) and return the structured JSON summary.\n\n{text}"}]
            )
            results.append(parse_json(r.content[0].text))
            print("    OK")
        except Exception as e:
            print(f"    Error: {e}")
    return results
 
def merge_results(client, partials):
    combined = json.dumps(partials, indent=2)
    print(f"Merging {len(partials)} partials")
    r = client.messages.create(
        model="claude-sonnet-4-20250514", max_tokens=8000,
        system=MERGE_PROMPT+combined,
        messages=[{"role":"user","content":"Merge these partial summaries into one comprehensive JSON summary."}]
    )
    return parse_json(r.content[0].text)
 
def parse_json(raw):
    clean = raw.strip()
    if "```" in clean:
        for part in clean.split("```"):
            part = part.strip()
            if part.startswith("json"):
                part = part[4:].strip()
            try:
                return json.loads(part)
            except Exception:
                continue
    return json.loads(clean)
 
if __name__ == "__main__":
    port = int(os.environ.get("PORT", 5000))
    app.run(host="0.0.0.0", port=port, debug=False)
 
